// Maximum non-overlapping intervals
public int maxActivities(int[][] intervals) {
    Arrays.sort(intervals, (a, b) -> a[1] - b[1]); // sort by end time
    int count = 1, lastEnd = intervals[0][1];
    for (int i = 1; i < intervals.length; i++) {
        if (intervals[i][0] >= lastEnd) { // starts after last ends
            count++;
            lastEnd = intervals[i][1];
        }
    }
    return count;
}

// Minimum number of meeting rooms (use max-heap/counting)
public int minMeetingRooms(int[][] intervals) {
    int[] starts = new int[intervals.length];
    int[] ends = new int[intervals.length];
    for (int i = 0; i < intervals.length; i++) {
        starts[i] = intervals[i][0];
        ends[i] = intervals[i][1];
    }
    Arrays.sort(starts);
    Arrays.sort(ends);
    int rooms = 0, endPtr = 0;
    for (int start : starts) {
        if (start < ends[endPtr]) rooms++;
        else endPtr++;
    }
    return rooms;
}

// Merge overlapping intervals
public int[][] mergeIntervals(int[][] intervals) {
    Arrays.sort(intervals, (a, b) -> a[0] - b[0]); // sort by start time
    List<int[]> merged = new ArrayList<>();
    for (int[] interval : intervals) {
        if (merged.isEmpty() || merged.getLast()[1] < interval[0]) {
            merged.add(interval);
        } else {
            merged.getLast()[1] = Math.max(merged.getLast()[1], interval[1]);
        }
    }
    return merged.toArray(new int[0][]);
}

// Jump Game I: can you reach the last index?
public boolean canJump(int[] nums) {
    int maxReach = 0;
    for (int i = 0; i < nums.length; i++) {
        if (i > maxReach) return false;
        maxReach = Math.max(maxReach, i + nums[i]);
    }
    return true;
}

// Jump Game II: minimum jumps to reach end
public int jump(int[] nums) {
    int jumps = 0, currEnd = 0, farthest = 0;
    for (int i = 0; i < nums.length - 1; i++) {
        farthest = Math.max(farthest, i + nums[i]);
        if (i == currEnd) { // reached end of current jump range
            jumps++;
            currEnd = farthest;
        }
    }
    return jumps;
}

// Jump Game VI: maximum score path (DP + deque)
public int maxResult(int[] nums, int k) {
    int n = nums.length;
    int[] dp = new int[n];
    dp[0] = nums[0];
    Deque<Integer> deque = new ArrayDeque<>();
    deque.offer(0);
    for (int i = 1; i < n; i++) {
        while (!deque.isEmpty() && deque.peek() < i - k) deque.poll();
        dp[i] = nums[i] + dp[deque.peek()];
        while (!deque.isEmpty() && dp[deque.peekLast()] <= dp[i]) deque.pollLast();
        deque.offer(i);
    }
    return dp[n - 1];
}

public int canCompleteCircuit(int[] gas, int[] cost) {
    int totalGas = 0, tank = 0, start = 0;
    for (int i = 0; i < gas.length; i++) {
        int diff = gas[i] - cost[i];
        totalGas += diff;
        tank += diff;
        if (tank < 0) {
            start = i + 1; // can't start from old start through i
            tank = 0;
        }
    }
    return totalGas >= 0 ? start : -1;
}

class Item {
    int weight, value;
    Item(int w, int v) { weight = w; value = v; }
}

public double fractionalKnapsack(Item[] items, int capacity) {
    // Sort by value/weight ratio descending
    Arrays.sort(items, (a, b) -> Double.compare(
        (double) b.value / b.weight,
        (double) a.value / a.weight
    ));
    double totalValue = 0;
    for (Item item : items) {
        if (capacity <= 0) break;
        if (item.weight <= capacity) {
            totalValue += item.value;
            capacity -= item.weight;
        } else {
            totalValue += (double) item.value * capacity / item.weight;
            capacity = 0;
        }
    }
    return totalValue;
}

// Task Scheduler (similar greedy: highest frequency first)
public int leastInterval(char[] tasks, int n) {
    int[] freq = new int[26];
    for (char c : tasks) freq[c - 'A']++;
    Arrays.sort(freq);
    int maxFreq = freq[25];
    int maxCount = 0;
    for (int f : freq) if (f == maxFreq) maxCount++;
    return Math.max(tasks.length, (maxFreq - 1) * (n + 1) + maxCount);
}
